                const delta = choice?.delta?.content;
                if (delta) {
                    roundText += delta;
                    accumulatedText += delta;
                    yield JSON.stringify({ content: delta, done: false });
                }

                if (choice?.finish_reason) {
                    finishReason = choice.finish_reason;
                }
