function mergeSearchResults(existing, nextResults, query) {
    const merged = [...existing];
    for (const result of nextResults || []) {
        if (!result?.url || merged.some((item) => item.url === result.url)) {
            continue;
        }
        merged.push({ ...result, query });
    }
    return merged;
}

